1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const ALIKE_BLOCK_SIZE = 3;
7	const ALIKE_BLOCK_PREMIUM = 60;
8	
9	const BASE_PREMIUM: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	type Item = { type: string; cursed?: boolean; enchantment?: number };
19	type Step = { items: Item[] };
20	type Scenario = { steps: Step[] };
21	
22	const groupByType = (items: Item[]): Item[][] => {
23	  const groups = Map.groupBy(items, (item) => item.type);
24	  return Array.from(groups.values());
25	};
26	
27	const sumBasePremiums = (items: Item[]): number =>
28	  items.reduce((acc, { type }) => acc + BASE_PREMIUM[type], 0);
29	
30	const basePremiumForGroup = (group: Item[]): number =>
31	  group.length === ALIKE_BLOCK_SIZE ? ALIKE_BLOCK_PREMIUM : sumBasePremiums(group);
32	
33	const basePremiumForItems = (items: Item[]): number =>
34	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
35	
36	const cursedSurcharge = (item: Item): number =>
37	  item.cursed ? BASE_PREMIUM[item.type] * CURSED_SURCHARGE_RATE : 0;
38	
39	const highEnchantmentSurcharge = (item: Item): number =>
40	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
41	    ? BASE_PREMIUM[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE
42	    : 0;
43	
44	const itemSurcharges = (items: Item[]): number =>
45	  items.reduce(
46	    (sum, item) => sum + cursedSurcharge(item) + highEnchantmentSurcharge(item),
47	    0,
48	  );
49	
50	const quotePremium = (items: Item[]): number => {
51	  const basePremium = basePremiumForItems(items);
52	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
53	  return Math.ceil(basePremium + itemSurcharges(items) + firstInsuranceSurcharge) + PROCESSING_FEE;
54	};
55	
56	export const runScenario = (scenario: Scenario): unknown => {
57	  const results = scenario.steps.map((step) => ({
58	    premium: quotePremium(step.items),
59	  }));
60	  return { results };
61	};
